step.action:
Prepare shared story context to inject into every sub-agent prompt:
      - story_key: {{story_key}}
      - story_id: {{story_id}} (e.g., "2.4")
      - epic_num: {{epic_num}}
      - story_num: {{story_num}}
      - story_title: {{story_title}}

step.output:
✅ **Parallel Research Complete**
      8 research agents returned. Context saved for dev-story reuse.
      is_ui_story: {{is_ui_story}}

step.action:
Add to story frontmatter or first comment block:
      - story_key: {{story_key}}
      - is_ui_story: {{is_ui_story}}
      - research_context_file: _bmad-output/parallel/research-context-{{story_key}}.md
      - skills_scanned: false

step.output:
📊 **IR Validation Complete — {{story_key}}**
      Agents: Requirements Traceability | Architecture Alignment | Story Quality | Dependency Risk
      Overall: {{ir_overall_status}}
      Total findings: {{ir_finding_count}}

**🎯 Story Ready — {{story_key}}**

      Story ID: {{story_id}}
      File: {{story_file}}
      Status: ready-for-dev
      Research Context: _bmad-output/parallel/research-context-{{story_key}}.md
      IR Report: _bmad-output/parallel/story-ir-report-{{story_key}}.md
      is_ui_story: {{is_ui_story}}
      IR findings fixed: {{fix_count}}
